package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithTrim() {
        CSVFormat original = CSVFormat.DEFAULT;
        // withTrim() should return a new CSVFormat with trim = true
        CSVFormat trimmed = original.withTrim();
        assertNotNull(trimmed);
        assertTrue(trimmed.getTrim());
        // original instance should remain unchanged (trim = false)
        assertFalse(original.getTrim());

        // withTrim(true) explicitly
        CSVFormat trimmedExplicit = original.withTrim(true);
        assertNotNull(trimmedExplicit);
        assertTrue(trimmedExplicit.getTrim());

        // withTrim(false) explicitly disables trimming
        CSVFormat notTrimmed = original.withTrim(false);
        assertNotNull(notTrimmed);
        assertFalse(notTrimmed.getTrim());

        // Using withTrim(true) on an instance that already has trim = true returns itself
        CSVFormat trimmed2 = trimmed.withTrim(true);
        assertSame(trimmed, trimmed2);

        // Using withTrim(false) on an instance with trim = true returns a different instance with trim = false
        CSVFormat trimmedFalse = trimmed.withTrim(false);
        assertNotSame(trimmed, trimmedFalse);
        assertFalse(trimmedFalse.getTrim());

        // Using withTrim(false) on instance with trim = false returns itself
        CSVFormat notTrimmed2 = notTrimmed.withTrim(false);
        assertSame(notTrimmed, notTrimmed2);
    }
}
